export function getSupplierEmail(website: string): string {
  try {
    const url = new URL(website);
    const domain = url.hostname.replace(/^www\./, "");
    return `info@${domain}`;
  } catch {
    return "info@supplier.com";
  }
}

export function getMarketplaceCategory(industry: string): string {
  const i = industry.toLowerCase();
  if (i.includes("ccaas") || i.includes("contact center") || i.includes("cpaas")) return "Contact Center";
  if (i.includes("ucaas") || i.includes("unified communications") || i.includes("voip") || i.includes("cloud communications")) return "Communications";
  if (i.includes("cybersecurity") || i.includes("security") || i.includes("sase") || i.includes("mdr")) return "Security";
  if (i.includes("data center") || i.includes("colocation")) return "Data Centers";
  if (i.includes("iot") || i.includes("internet of things")) return "IoT";
  if (i.includes("sd-wan") || i.includes("networking") || i.includes("naas")) return "Networking";
  if (i.includes("managed it") || i.includes("it services") || i.includes("msp")) return "Managed IT";
  if (i.includes("cloud") || i.includes("saas")) return "Cloud";
  if (i.includes("payment") || i.includes("fintech") || i.includes("financial")) return "Payments";
  if (i.includes("ai") || i.includes("artificial intelligence") || i.includes("conversational")) return "AI & Automation";
  if (i.includes("telecom") || i.includes("fiber") || i.includes("broadband") || i.includes("isp")) return "Connectivity";
  if (i.includes("mobility") || i.includes("fleet") || i.includes("mobile")) return "Mobility";
  if (i.includes("expense management") || i.includes("tem")) return "Expense Management";
  if (i.includes("physical security") || i.includes("psaas")) return "Physical Security";
  return "Technology";
}

export function getSupplierCatalogSummary(): string {
  const lines = SUPPLIERS.map(s => {
    const cat = getMarketplaceCategory(s.industry);
    const keyP = s.keyProducts.split(",").slice(0, 3).join(",");
    return `- ${s.name} [${cat}] (${s.website}): ${keyP}`;
  });
  return lines.join("\n");
}
